// ---------------------------------------------------------------------------
// F. Loading state — shimmer skeleton visible when pending stub
// ---------------------------------------------------------------------------

describe('AI Coach — loading skeleton while fetch is in-flight', () => {
  it('shows shimmer loading skeleton before insight fetch resolves', () => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubActivity()
    stubDashboard()
    stubRaceLog()
    stubStreams()

    // Delay the insight response so loading state is catchable
    cy.intercept('GET', `${AI_EP}*`, (req) => {
      req.reply((res) => {
        res.setDelay(700)
        res.send({ statusCode: 200, body: { data: [] } })
      })
    }).as('getInsightDelayed')

    cy.viewport(1280, 720)
    cy.visit(DETAIL_URL)
    cy.wait('@getActivity')

    cy.get(`#${IDS.ai_insight_loading}`).should('exist')
  })

  it('shows pending shimmer skeleton when insight status is pending', () => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubActivity()
    stubDashboard()
    stubRaceLog()
    stubStreams()
    stubInsightPending()
    visitAndWait()
    cy.wait('@getInsightPending')

    cy.get(`#${IDS.ai_insight_pending_skeleton}`).should('exist')
    cy.get(`#${IDS.ai_insight_pending_bar}`).should('exist')
  })
})

// ---------------------------------------------------------------------------
// G. Rotating copy during pending (cy.clock, advance 6s)
// ---------------------------------------------------------------------------

describe('AI Coach — rotating status copy during pending state', () => {
  it('shows initial copy at 0s and different copy after 6s', () => {
    // Use cy.clock() before visit so the component initialises with controlled time
    cy.clock()

    cy.setupApiAuthCookies()
    stubRtUsers()
    stubActivity()
    stubDashboard()
    stubRaceLog()
    stubStreams()
    stubInsightPending()

    cy.viewport(1280, 720)
    cy.visit(DETAIL_URL)
    cy.wait('@getActivity')
    cy.wait('@getInsightPending')

    // Ensure the pending section is fully rendered before ticking the clock,
    // so the fake setInterval(1000) timer is registered before cy.tick fires it
    cy.get(`#${IDS.ai_insight_pending}`).should('exist')

    // At 0s elapsed: first copy bucket applies (< 5s)
    cy.get(`#${IDS.ai_insight_pending_status}`)
      .should('exist')
      .and('contain.text', 'Reading your run data...')

    // Advance clock 6 seconds to reach the second copy bucket (5–15s)
    cy.tick(6000)

    cy.get(`#${IDS.ai_insight_pending_status}`).should(
      'contain.text',
      'Analyzing pace, HR zones, and splits...'
    )
  })
})

// ---------------------------------------------------------------------------
// H. Long-wait hint after 60s (cy.clock, advance 61000ms)
// ---------------------------------------------------------------------------

describe('AI Coach — long-wait hint appears after 60 seconds', () => {
  it('long-wait hint is hidden initially and appears after 60s', () => {
    cy.clock()

    cy.setupApiAuthCookies()
    stubRtUsers()
    stubActivity()
    stubDashboard()
    stubRaceLog()
    stubStreams()
    stubInsightPending()

    cy.viewport(1280, 720)
    cy.visit(DETAIL_URL)
    cy.wait('@getActivity')
    cy.wait('@getInsightPending')

    // Ensure the pending section is fully rendered before ticking the clock,
    // so the fake setTimeout(60000) timer is registered before cy.tick fires it
    cy.get(`#${IDS.ai_insight_pending}`).should('exist')

    // Long-wait hint should NOT exist before 60s
    cy.get(`#${IDS.ai_insight_long_wait_hint}`).should('not.exist')

    // Advance clock past the 60s threshold
    cy.tick(61000)

    cy.get(`#${IDS.ai_insight_long_wait_hint}`)
      .should('exist')
      .and('contain.text', 'This is taking longer than usual')
  })

  it('long-wait hint contains a "Try again" action button', () => {
    cy.clock()

    cy.setupApiAuthCookies()
    stubRtUsers()
    stubActivity()
    stubDashboard()
    stubRaceLog()
    stubStreams()
    stubInsightPending()

    cy.viewport(1280, 720)
    cy.visit(DETAIL_URL)
    cy.wait('@getActivity')
    cy.wait('@getInsightPending')

    cy.tick(61000)

    cy.get(`#${IDS.ai_insight_long_wait_hint}`)
      .scrollIntoView()
      .within(() => {
        cy.contains('Try again').should('be.visible')
      })
  })
})

