describe('AI Coach — comparison section renders in content state', () => {
  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubActivity()
    stubDashboard()
    stubRaceLog()
    stubStreams()
    stubInsight({ data: [completedInsight] })
    visitAndWait()
    cy.wait('@getInsight')
  })

  it('compare section is rendered when insight is completed', () => {
    cy.get(`#${IDS.ai_insight_compare_section}`).scrollIntoView().should('exist').and('be.visible')
  })

  it('compare trigger button is rendered inside compare section', () => {
    cy.get(`#${IDS.ai_insight_compare_section}`).within(() => {
      cy.get(`#${IDS.ai_insight_compare_trigger}`)
        .scrollIntoView()
        .should('exist')
        .and('be.visible')
    })
  })

  it('compare trigger button contains "Compare with another run" text', () => {
    cy.get(`#${IDS.ai_insight_compare_trigger}`)
      .scrollIntoView()
      .should('contain.text', 'Compare with another run')
  })

  it('compare section and trigger are absent in empty state', () => {
    // Content state is rendered; scroll into view before checking visibility
    cy.get(`#${IDS.ai_insight_content}`).scrollIntoView().should('be.visible')
    cy.get(`#${IDS.ai_insight_compare_section}`).should('exist')
    // Confirm no Get Recommendation btn (needs a selected activity first)
    cy.get(`#${IDS.ai_insight_get_recommendation_btn}`).should('not.exist')
  })
})

