// K. Activity comparison — activity list renders inside popover
// ---------------------------------------------------------------------------

describe('AI Coach — activity list renders inside comparison popover', () => {
  const comparisonActivities = [
    {
      id: 'compare-act-001',
      name: 'Morning Run',
      started_at: '2026-05-20T06:00:00Z',
      distance_m: 8000,
      avg_pace_sec_per_km: 370,
    },
    {
      id: 'compare-act-002',
      name: 'Easy Recovery',
      started_at: '2026-05-18T07:00:00Z',
      distance_m: 5000,
      avg_pace_sec_per_km: 400,
    },
  ]

  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubActivity()
    stubDashboard()
    stubRaceLog()
    stubStreams()
    stubInsight({ data: [completedInsight] })
    stubActivitiesList(comparisonActivities)
    cy.viewport(1280, 720)
    cy.visit(DETAIL_URL)
    cy.wait('@getActivity')
    cy.wait('@getInsight')
  })

  it('comparison command container is rendered inside the popover', () => {
    cy.get(`#${IDS.ai_insight_compare_trigger}`).scrollIntoView().click()
    cy.wait('@getActivities')

    cy.get(`#${IDS.ai_insight_compare_popover}`)
      .should('be.visible')
      .within(() => {
        cy.get(`#${IDS.ai_insight_compare_command}`).should('exist')
      })
  })

  it('activity list shows the stubbed activities grouped by month', () => {
    cy.get(`#${IDS.ai_insight_compare_trigger}`).scrollIntoView().click()
    cy.wait('@getActivities')

    cy.get(`#${IDS.ai_insight_compare_popover}`).within(() => {
      // en-US locale: toLocaleDateString('en-US', { day: 'numeric', month: 'short' }) → "May 20"
      cy.contains('May 20').should('exist')
      cy.contains('May 18').should('exist')
    })
  })

  it('selecting an activity from the list closes the popover', () => {
    cy.get(`#${IDS.ai_insight_compare_trigger}`).scrollIntoView().click()
    cy.wait('@getActivities')

    // Click the first activity button in the popover list
    cy.get(`#${IDS.ai_insight_compare_popover}`).find('button').first().click()

    // Popover closes after selection (allow time for Radix animation)
    cy.get(`#${IDS.ai_insight_compare_popover}`, { timeout: 8000 }).should('not.exist')
    // Compare pill appears with the selected activity info
    cy.get(`#${IDS.ai_insight_compare_pill}`).should('exist')
  })
})

// ---------------------------------------------------------------------------
// L. Get Recommendation button fires compare_activity focus
// ---------------------------------------------------------------------------

describe('AI Coach — Get Recommendation button fires compare_activity generate', () => {
  const comparisonActivities = [
    {
      id: 'compare-act-003',
      name: 'Interval Session',
      started_at: '2026-05-15T05:30:00Z',
      distance_m: 6000,
      avg_pace_sec_per_km: 320,
    },
  ]

  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubActivity()
    stubDashboard()
    stubRaceLog()
    stubStreams()
    stubInsight({ data: [completedInsight] })
    stubActivitiesList(comparisonActivities)
    stubGeneratePost()
    cy.viewport(1280, 720)
    cy.visit(DETAIL_URL)
    cy.wait('@getActivity')
    cy.wait('@getInsight')
  })

  it('Get Recommendation button is not visible until a comparison activity is selected', () => {
    cy.get(`#${IDS.ai_insight_get_recommendation_btn}`).should('not.exist')
  })

  it('Get Recommendation button appears after selecting a comparison activity', () => {
    // Open popover and select an activity
    cy.get(`#${IDS.ai_insight_compare_trigger}`).scrollIntoView().click()
    cy.wait('@getActivities')

    cy.get(`#${IDS.ai_insight_compare_popover}`).within(() => {
      cy.contains('May 15').click()
    })

    // Get Recommendation button should now be visible
    cy.get(`#${IDS.ai_insight_get_recommendation_btn}`)
      .scrollIntoView()
      .should('be.visible')
      .and('contain.text', 'Get Recommendation')
  })

  it('clicking Get Recommendation fires POST generate with compare_activity focus', () => {
    // Select a comparison activity first
    cy.get(`#${IDS.ai_insight_compare_trigger}`).scrollIntoView().click()
    cy.wait('@getActivities')

    cy.get(`#${IDS.ai_insight_compare_popover}`).within(() => {
      cy.contains('May 15').click()
    })

    // Click Get Recommendation
    cy.get(`#${IDS.ai_insight_get_recommendation_btn}`).scrollIntoView().click()

    // POST generate should have been called
    cy.wait('@postGenerate').then((interception) => {
      expect(interception.request.body).to.have.property('focus', 'compare_activity')
    })
  })

  it('Get Recommendation transitions card to pending state after POST', () => {
    // After POST returns 202, component sets insight to pending
    cy.get(`#${IDS.ai_insight_compare_trigger}`).scrollIntoView().click()
    cy.wait('@getActivities')

    cy.get(`#${IDS.ai_insight_compare_popover}`).within(() => {
      cy.contains('May 15').click()
    })

    // Stub subsequent GET to return pending
    cy.intercept('GET', `${AI_EP}*`, {
      statusCode: 200,
      body: {
        data: [
          {
            id: 'insight-compare-pending',
            insight_type: 'post_activity',
            status: 'pending',
            is_valid: true,
            title: null,
            content: null,
            data_refs: { focus: 'compare_activity' },
            acknowledged: false,
            created_at: '2026-05-31T09:00:00Z',
          },
        ],
      },
    }).as('getInsightPendingCompare')

    cy.get(`#${IDS.ai_insight_get_recommendation_btn}`).scrollIntoView().click()
    cy.wait('@postGenerate')

    // Card should now show pending state
    cy.get(`#${IDS.ai_insight_pending}`).should('exist')
  })
})
